test "compose clip repro: wedge points stay inside subject-and-face intersection" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const a = arena.allocator();
    const r = try boolean.compute(a, &SUBJECT, &FACE, .intersect);
    // Points in the open bay water (inside S0, inside no hole, inside the face box):
    // these MUST be in the intersection. The wedge artifact excluded them.
    const probes = [_]Pt{
        .{ .x = 2794, .y = 45 },
        .{ .x = 2740, .y = 150 },
        .{ .x = 2600, .y = 300 },
        .{ .x = 2900, .y = 200 },
    };
    for (probes) |q| {
        try std.testing.expect(boolean.pointInEvenOdd(&SUBJECT, q.x, q.y)); // sanity: in subject
        try std.testing.expect(boolean.pointInEvenOdd(&FACE, q.x, q.y)); // sanity: in face
        if (!boolean.pointInEvenOdd(r, q.x, q.y)) {
            std.debug.print("wedge point ({d},{d}) missing from intersection\n", .{ q.x, q.y });
            return error.WedgeExcluded;
        }
    }
}

