const SM_SUBJECT = [_][]const Pt{&SM_S0};
const SM_FACE = [_][]const Pt{&SM_F0};

test "compose clip repro: micro-subdivided seam edge with duplicate vertices" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const a = arena.allocator();
    const before = boolean.open_chain_walks;
    const r = try boolean.compute(a, &SM_SUBJECT, &SM_FACE, .intersect);
    try std.testing.expectEqual(before, boolean.open_chain_walks); // every walk must close
    // Interior of subject ∩ face must be present.
    const probes = [_]Pt{ .{ .x = 1990, .y = 1100 }, .{ .x = 2005, .y = 1150 }, .{ .x = 1975, .y = 1190 } };
    for (probes) |q| {
        try std.testing.expect(boolean.pointInEvenOdd(&SM_SUBJECT, q.x, q.y));
        try std.testing.expect(boolean.pointInEvenOdd(&SM_FACE, q.x, q.y));
        try std.testing.expect(boolean.pointInEvenOdd(r, q.x, q.y));
    }
}

